{"capability_manifest": {"pCategorys": {"field": "pCategorys", "operators": ["CONTAINS", "NOT_CONTAINS"], "value_types": ["enum"], "description": "表示客户持有的寿险险种大类，如年金保险、医疗保险、疾病保险、意外伤害保险等，不表示具体产品名称。", "definition": "表示客户持有的寿险险种大类，如年金保险、医疗保险、疾病保险、意外伤害保险等，不表示具体产品名称。", "enums": [], "unit": "", "notes": "医疗险/重疾险/年金险等口语应归到险种大类；具体产品简称或产品全称应映射到 polNoInfo.plancodeinfo.abbrname 或 polNoInfo.plancodeinfo.planfullname。"}}, "semantic_equivalence_rules": {}, "value_mappings": {"pCategorys": {"医疗险": "医疗保险", "医疗产品": "医疗保险", "定期险": "定期寿险", "重疾险": "疾病保险", "重疾产品": "疾病保险", "重大疾病险": "疾病保险", "重大疾病保险": "疾病保险", "疾病产品": "疾病保险", "护理险": "护理保险", "护理产品": "护理保险", "意外险": "意外伤害保险", "意外伤害险": "意外伤害保险", "意外产品": "意外保险", "终身寿": "终身寿险"}}, "enhanced_rules": {"rules": [{"name": "险种-持有", "enum_ref": "pCategorys", "patterns_template": ["{SEARCH}{position}?{enum}(?:产品|保险)?(?:的客户|客户|名单|有哪些人|有哪些|的人|人|的)?", "{SEARCH}{enum}(?:产品|保险)?(?:的客户|客户|的人|人|名单|有哪些人|有哪些|的)?", "{SEARCH}(?:产品类别|险种)(?:包含|为|是)?{enum}(?:保险)?(?:的客户|客户)?", "{SEARCH}{position}?{enum}(?:产品|保险)?名单", "{SEARCH}{enum}(?:产品)?(?:名单)?", "{SEARCH}{position}?{enum}(?:产品|保险)?有哪些", "{SEARCH}{enum}(?:产品|保险)?有哪些"], "field": "pCategorys", "operator": "CONTAINS", "value_type": "capture", "value": {"group": 1}, "priority": 8, "negation_support": true}, {"name": "险种-未配置", "enum_ref": "pCategorys", "patterns_template": ["{SEARCH}{negation}{enum}(?:产品|保险)?(?:的客户|客户)?", "{SEARCH}{negation}{enum}(?:产品|保险)?(?:的人|人)?"], "field": "pCategorys", "operator": "NOT_CONTAINS", "value_type": "capture", "value": {"group": 1}, "priority": 9}], "composite_rules": [{"name": "姓名+出生年份", "patterns": ["{SEARCH}【姓名-模糊匹配】【出生年份-片段】(?:的客户|客户)?"], "priority": 40}, {"name": "投保险种名称+投保险种类型", "patterns": ["【投保险种名称】(?:[的、，, 和及与且]{0,2})?【投保险种类型】(?:的客户|客户|名单|的人|人)?", "【投保险种类型】(?:[的、，, 和及与且]{0,2})?【投保险种名称】(?:的客户|客户|名单|的人|人)?"], "priority": 24}, {"name": "投保险种简称+投保险种类型", "ignore_case": true, "patterns": ["【投保险种简称】(?:[的、，, 和及与且]{0,2})?【投保险种类型】(?:的客户|客户|名单|的人|人)?", "【投保险种类型】(?:[的、，, 和及与且]{0,2})?【投保险种简称】(?:的客户|客户|名单|的人|人)?"], "priority": 24}, {"name": "投保险种简称+保单状态", "ignore_case": true, "patterns": ["【投保险种简称】(?:[的、，, 和及与且]{0,2})?【保单状态】(?:的客户|客户|名单|的人|人)?", "【保单状态】(?:[的、，, 和及与且]{0,2})?【投保险种简称】(?:的客户|客户|名单|的人|人)?", "【投保险种简称】(?:[的、，, 和及与且]{0,2})?【保单状态-有效汇总】", "【保单状态-有效汇总】(?:[的、，, 和及与且]{0,2})?【投保险种简称】(?:的客户|客户|名单|的人|人)?", "【投保险种简称】(?:[的、，, 和及与且]{0,2})?【保单状态-未有效汇总】", "【保单状态-未有效汇总】(?:[的、，, 和及与且]{0,2})?【投保险种简称】(?:的客户|客户|名单|的人|人)?"], "priority": 24}, {"name": "投保险种简称+保单到期时间", "patterns": ["【投保险种简称】(?:[的、，, 和及与且]{0,4})?【保单到期时间-近期】(?:的客户|客户|名单|的人|人)?", "【保单到期时间-近期】(?:[的、，, 和及与且]{0,4})?【投保险种简称】(?:的客户|客户|名单|的人|人)?"], "priority": 24}, {"name": "投保险种名称+保单状态", "ignore_case": true, "patterns": ["【投保险种名称】(?:[的、，, 和及与且]{0,2})?【保单状态】(?:的客户|客户|名单|的人|人)?", "【保单状态】(?:[的、，, 和及与且]{0,2})?【投保险种名称】(?:的客户|客户|名单|的人|人)?", "【投保险种名称】(?:[的、，, 和及与且]{0,2})?【保单状态-有效汇总】", "【投保险种名称】(?:[的、，, 和及与且]{0,2})?【保单状态-未有效汇总】", "【保单状态-未有效汇总】(?:[的、，, 和及与且]{0,2})?【投保险种名称】(?:的客户|客户|名单|的人|人)?"], "priority": 24}, {"name": "险种到期", "patterns": ["{SEARCH}【险种-持有】(?:[的、，, 和及与且]{0,2})?【保单-已到期】(?:的客户|客户)?"], "priority": 15}, {"name": "险种类型到期", "patterns": ["{SEARCH}【投保险种类型】(?:[的、，, 和及与且]{0,2})?【保单-已到期】(?:的客户|客户)?"], "priority": 15}, {"name": "产品类型到期", "patterns": ["{SEARCH}【持有产品类型-持有】(?:[的、，, 和及与且]{0,2})?【保单-已到期】(?:的客户|客户)?"], "priority": 15}, {"name": "年龄GTE+婚姻+有子女+未配置险种", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【家庭成员关系-有】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【家庭成员关系-有】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?"], "priority": 35}, {"name": "年龄GTE+婚姻+性别", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【性别-枚举】(?:性)?(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【性别-枚举】(?:性)?(?:[的、，, ]{0,3})?【婚姻状况】(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【性别-枚举】(?:性)?(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【性别-枚举】(?:性)?(?:[的、，, ]{0,3})?【婚姻状况】(?:[的]{0,2})?(?:的客户|客户)?"], "priority": 30}, {"name": "年龄GTE+婚姻+未配置险种", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【婚姻状况】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?"], "priority": 30}, {"name": "年龄GTE+有子女+未配置险种", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【家庭成员关系-有】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【家庭成员关系-有】(?:[的、，, ]{0,3})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?"], "priority": 30}, {"name": "年龄精确+有子女+未配置险种", "patterns": ["{SEARCH}【年龄-精确】(?:[的、，, 还就也]{0,4})?【家庭成员关系-有】(?:[的、，, 还就也]{0,4})?【险种-未配置】(?:[的]{0,2})?(?:的客户|客户)?"], "priority": 30}, {"name": "年龄以上+客户是父母", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?父母(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?父母(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}]}, {"name": "年龄精确+客户是父母", "patterns": ["{SEARCH}【年龄-精确】(?:[的、，, ]{0,3})?父母(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}]}, {"name": "年龄范围+客户是父母", "patterns": ["{SEARCH}【年龄-范围】(?:[的、，, ]{0,3})?父母(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}]}, {"name": "年龄以上+宝妈", "patterns": ["{SEARCH}【年龄-以上】(?:[的、，, ]{0,3})?【宝妈】(?:的客户|客户)?", "{SEARCH}【年龄-及以上】(?:[的、，, ]{0,3})?【宝妈】(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}, {"field": "familyInfo.familyclientage", "operator": "RANGE", "value": {"min": 0, "max": 6}}]}, {"name": "年龄精确+宝妈", "patterns": ["{SEARCH}【年龄-精确】(?:[的、，, ]{0,3})?【宝妈】(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}, {"field": "familyInfo.familyclientage", "operator": "RANGE", "value": {"min": 0, "max": 6}}]}, {"name": "年龄范围+宝妈", "patterns": ["{SEARCH}【年龄-范围】(?:[的、，, ]{0,3})?【宝妈】(?:的客户|客户)?"], "priority": 24, "extra_conditions": [{"field": "familyInfo.familyrelation", "operator": "CONTAINS", "value": "子女"}, {"field": "familyInfo.familyclientage", "operator": "RANGE", "value": {"min": 0, "max": 6}}]}], "composite_rules_truncated": true, "negation_words": ["没有配置", "未配置", "没配置", "未购买", "没有", "没买", "未买", "缺少", "缺失", "没", "无", "不", "缺", "未", "非"]}, "critical_intent_dimensions": ["target_population", "field_semantics", "operator", "value_or_unit", "boolean_logic", "unsupported_or_out_of_boundary_request"], "expected_intent": null, "run_trace": {"trace_id": "c598b164-09e5-426b-9858-6e0c43c0dcc4", "project_id": "client_search", "case_id": "mock-agent-client_search-cdd7df11", "input": {"extra_input_params": {"pCategorys": "重疾险"}, "session_id": "session_001", "source": "insurance_search", "trace_id": "trace_001", "user_id": "default_user", "user_text": "帮我看看公司里所有买了重疾险的客户都有谁"}, "normalized_request": {"user_text": "帮我看看公司里所有买了重疾险的客户都有谁", "user_id": "default_user", "trace_id": "trace_001", "session_id": "session_001", "source": "insurance_search", "extra_input_params": {"pCategorys": "重疾险"}}, "raw_response": {"code": 0, "msg": "操作成功", "data": {"robot_text": "产品类别为疾病保险的客户", "end_flag": 1, "extra_output_params": {"query": "帮我看看公司里所有买了重疾险的客户都有谁", "query_logic": "AND", "conditions": [{"field": "pCategorys", "operator": "MATCH", "value": "疾病保险"}], "matched_level": 4, "rewritten_query": "帮我看看公司里所有买了疾病保险的客户都有谁", "matched_patterns": "### 当前时间
